import React, { useState, useEffect, useRef } from 'react';
import './ChatModal.css';
import { chatService } from '../services/firebaseService';

const ChatModal = ({ onClose }) => {
  const [messages, setMessages] = useState([]);
  const [newMessage, setNewMessage] = useState('');
  const [loading, setLoading] = useState(true);
  const [sending, setSending] = useState(false);
  const messagesEndRef = useRef(null);
  const currentUser = `User${Math.floor(Math.random() * 1000)}`;

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  const formatTime = (timestamp) => {
    if (!timestamp) return 'now';
    
    const now = new Date();
    const messageTime = timestamp.toDate ? timestamp.toDate() : new Date(timestamp);
    const diffInMinutes = Math.floor((now - messageTime) / (1000 * 60));
    
    if (diffInMinutes < 1) return 'now';
    if (diffInMinutes < 60) return `${diffInMinutes} min ago`;
    return messageTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const fetchMessages = async () => {
    try {
      setLoading(true);
      const fetchedMessages = await chatService.getMessages(50);
      setMessages(fetchedMessages);
    } catch (error) {
      console.error('Error fetching messages:', error);
      // Fallback to sample messages
      setMessages([
        {
          id: 'sample1',
          user: 'SupportBot',
          message: 'Welcome to our support chat! How can we help you today?',
          createdAt: new Date(Date.now() - 5 * 60 * 1000),
          isSupport: true
        },
        {
          id: 'sample2',
          user: 'User123',
          message: 'Hi, I\'ve been feeling overwhelmed lately.',
          createdAt: new Date(Date.now() - 3 * 60 * 1000),
          isSupport: false
        },
        {
          id: 'sample3',
          user: 'Peer456',
          message: 'I understand that feeling. You\'re not alone in this.',
          createdAt: new Date(Date.now() - 1 * 60 * 1000),
          isSupport: false
        }
      ]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchMessages();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSendMessage = (e) => {
    e.preventDefault();
    if (newMessage.trim()) {
      const message = {
        id: messages.length + 1,
        user: 'You',
        message: newMessage,
        time: 'now',
        isSupport: false
      };
      setMessages([...messages, message]);
      setNewMessage('');
    }
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal chat-modal" onClick={(e) => e.stopPropagation()}>
        <button className="modal-close" onClick={onClose}>×</button>
        
        <div className="chat-header">
          <h2>Chat</h2>
          <button className="more-options">⋯</button>
        </div>

        <div className="chat-messages">
          {messages.map((msg) => (
            <div key={msg.id} className={`message ${msg.isSupport ? 'support' : 'user'}`}>
              <div className="message-header">
                <span className="message-user">
                  {msg.isSupport ? '👤' : '🟢'} {msg.user}
                </span>
                <span className="message-time">{msg.time}</span>
              </div>
              <div className="message-content">{msg.message}</div>
              <div className="message-actions">
                <button className="action-btn">💬 Support</button>
                <button className="action-btn">👍 {msg.isSupport ? 'Helpful' : 'Follow'}</button>
              </div>
            </div>
          ))}
        </div>

        <form onSubmit={handleSendMessage} className="chat-input-form">
          <input
            type="text"
            value={newMessage}
            onChange={(e) => setNewMessage(e.target.value)}
            placeholder="Type a message..."
            className="chat-input"
          />
          <button type="submit" className="send-btn">Send</button>
        </form>
      </div>
    </div>
  );
};

export default ChatModal;
